CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE TABLE IF NOT EXISTS roles(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),name varchar(50) UNIQUE NOT NULL,description text);
CREATE TABLE IF NOT EXISTS permissions(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),code varchar(100) UNIQUE NOT NULL,description text);
CREATE TABLE IF NOT EXISTS role_permissions(role_id uuid REFERENCES roles(id) ON DELETE CASCADE,permission_id uuid REFERENCES permissions(id) ON DELETE CASCADE,PRIMARY KEY(role_id,permission_id));
CREATE TABLE IF NOT EXISTS departments(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),name varchar(255) NOT NULL,code varchar(50) UNIQUE,contact_name varchar(150),phone varchar(50),created_at timestamptz DEFAULT now(),updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS users(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),name varchar(150) NOT NULL,email varchar(255) UNIQUE NOT NULL,password_hash text NOT NULL,role_id uuid NOT NULL REFERENCES roles(id),department_id uuid REFERENCES departments(id),is_active boolean DEFAULT true,created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS partner_organizations(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),name varchar(255) NOT NULL,type varchar(80),country varchar(100) DEFAULT 'ไทย',address text,contact_name varchar(150),email varchar(255),phone varchar(50),created_at timestamptz DEFAULT now(),updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS collaborations(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),code varchar(80) UNIQUE NOT NULL,title_th text NOT NULL,type varchar(20) NOT NULL CHECK(type IN('MOU','MOA','LOI','AGREEMENT','PROJECT')),department_id uuid REFERENCES departments(id),start_date date,end_date date,status varchar(30) DEFAULT 'DRAFT' CHECK(status IN('DRAFT','PENDING','ACTIVE','EXPIRED','CANCELLED')),objective text,outcome text,created_by uuid REFERENCES users(id),created_at timestamptz DEFAULT now(),updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS collaboration_partners(collaboration_id uuid REFERENCES collaborations(id) ON DELETE CASCADE,partner_id uuid REFERENCES partner_organizations(id) ON DELETE CASCADE,PRIMARY KEY(collaboration_id,partner_id));
CREATE TABLE IF NOT EXISTS collaboration_activities(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),collaboration_id uuid REFERENCES collaborations(id) ON DELETE CASCADE,title text NOT NULL,activity_date date,description text,result text,created_by uuid REFERENCES users(id),created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS documents(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),collaboration_id uuid REFERENCES collaborations(id) ON DELETE CASCADE,file_name text NOT NULL,file_path text NOT NULL,mime_type varchar(150),file_size integer,uploaded_by uuid REFERENCES users(id),created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS workflow_logs(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),user_id uuid REFERENCES users(id),action varchar(40) NOT NULL,entity varchar(80) NOT NULL,entity_id uuid,detail jsonb DEFAULT '{}'::jsonb,created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS notifications(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),user_id uuid REFERENCES users(id),collaboration_id uuid REFERENCES collaborations(id) ON DELETE CASCADE,title text NOT NULL,message text NOT NULL,type varchar(30) DEFAULT 'EXPIRATION',is_read boolean DEFAULT false,created_at timestamptz DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_collaborations_end_date ON collaborations(end_date); CREATE INDEX IF NOT EXISTS idx_collaborations_status ON collaborations(status);
